items: {
    "properties": {
        "entries": {
            "items": {
                "description": "TFA Entry.",
                "properties": {
                    "created": {
                        "description": "Creation time of this entry as unix epoch.",
                        "type": "integer"
                    },
                    "description": {
                        "description": "User chosen description for this entry.",
                        "type": "string"
                    },
                    "enable": {
                        "default": 1,
                        "description": "Whether this TFA entry is currently enabled.",
                        "optional": 1,
                        "type": "boolean"
                    },
                    "id": {
                        "description": "The id used to reference this entry.",
                        "type": "string"
                    },
                    "type": {
                        "description": "TFA Entry Type.",
                        "enum": [
                            "totp",
                            "u2f",
                            "webauthn",
                            "recovery",
                            "yubico"
                        ],
                        "type": "string"
                    }
                },
                "type": "object"
            },
            "type": "array",
            "name": "entries",
            "optional": false,
            "id": "pmx-param-schema-1"
        },
        "tfa-locked-until": {
            "description": "Contains a timestamp until when a user is locked out of 2nd factors.",
            "optional": true,
            "type": "integer",
            "name": "tfa-locked-until",
            "id": "pmx-param-schema-2"
        },
        "totp-locked": {
            "description": "True if the user is currently locked out of TOTP factors.",
            "optional": true,
            "type": "boolean",
            "name": "totp-locked",
            "id": "pmx-param-schema-3"
        },
        "userid": {
            "description": "User this entry belongs to.",
            "type": "string",
            "name": "userid",
            "optional": false,
            "id": "pmx-param-schema-4"
        }
    },
    "type": "object"
}

