items: {
    "properties": {
        "comment": {
            "maxLength": 2048,
            "optional": true,
            "type": "string",
            "name": "comment",
            "id": "pmx-param-schema-16"
        },
        "email": {
            "format": "email-opt",
            "maxLength": 254,
            "optional": true,
            "type": "string",
            "name": "email",
            "id": "pmx-param-schema-17"
        },
        "enable": {
            "default": 1,
            "description": "Enable the account (default). You can set this to '0' to disable the account",
            "optional": true,
            "type": "boolean",
            "name": "enable",
            "id": "pmx-param-schema-18"
        },
        "expire": {
            "description": "Account expiration date (seconds since epoch). '0' means no expiration date.",
            "minimum": 0,
            "optional": true,
            "type": "integer",
            "name": "expire",
            "id": "pmx-param-schema-19"
        },
        "firstname": {
            "maxLength": 1024,
            "optional": true,
            "type": "string",
            "name": "firstname",
            "id": "pmx-param-schema-20"
        },
        "groups": {
            "format": "pve-groupid-list",
            "optional": true,
            "type": "string",
            "name": "groups",
            "id": "pmx-param-schema-21"
        },
        "keys": {
            "description": "Keys for two factor auth (yubico).",
            "optional": true,
            "pattern": "[0-9a-zA-Z!=]{0,4096}",
            "type": "string",
            "name": "keys",
            "id": "pmx-param-schema-22"
        },
        "lastname": {
            "maxLength": 1024,
            "optional": true,
            "type": "string",
            "name": "lastname",
            "id": "pmx-param-schema-23"
        },
        "realm-type": {
            "description": "The type of the users realm",
            "format": "pve-realm",
            "optional": true,
            "type": "string",
            "name": "realm-type",
            "id": "pmx-param-schema-24"
        },
        "tfa-locked-until": {
            "description": "Contains a timestamp until when a user is locked out of 2nd factors.",
            "optional": true,
            "type": "integer",
            "name": "tfa-locked-until",
            "id": "pmx-param-schema-25"
        },
        "tokens": {
            "items": {
                "properties": {
                    "comment": {
                        "optional": 1,
                        "type": "string"
                    },
                    "expire": {
                        "default": "same as user",
                        "description": "API token expiration date (seconds since epoch). '0' means no expiration date.",
                        "minimum": 0,
                        "optional": 1,
                        "type": "integer"
                    },
                    "privsep": {
                        "default": 1,
                        "description": "Restrict API token privileges with separate ACLs (default), or give full privileges of corresponding user.",
                        "optional": 1,
                        "type": "boolean"
                    },
                    "tokenid": {
                        "description": "User-specific token identifier.",
                        "pattern": "(?^:[A-Za-z][A-Za-z0-9\\.\\-_]+)",
                        "type": "string"
                    }
                },
                "type": "object"
            },
            "optional": true,
            "type": "array",
            "name": "tokens",
            "id": "pmx-param-schema-26"
        },
        "totp-locked": {
            "description": "True if the user is currently locked out of TOTP factors.",
            "optional": true,
            "type": "boolean",
            "name": "totp-locked",
            "id": "pmx-param-schema-27"
        },
        "userid": {
            "description": "Full User ID, in the `name@realm` format.",
            "format": "pve-userid",
            "maxLength": 64,
            "type": "string",
            "name": "userid",
            "optional": false,
            "id": "pmx-param-schema-28"
        }
    },
    "type": "object"
}

